const message = $json.body?.message;
if (!message?.chat?.id) {
  return [];
}

const text = (message.text || message.caption || '').trim();
if (!text) {
  return [];
}

return [{
  json: {
    chat_id: String(message.chat.id),
    user_text: text,
    telegram_date: message.date ? new Date(message.date * 1000).toISOString() : new Date().toISOString(),
    telegram_message_id: message.message_id || null,
    from: {
      id: message.from?.id ? String(message.from.id) : null,
      username: message.from?.username || null,
      first_name: message.from?.first_name || null
    }
  }
}];

const fs = require('fs');
const dbPath = '/home/node/.n8n/telegram-message-db.json';
const timeZone = 'Asia/Aden';
const now = new Date();
const nowIso = now.toISOString();

function loadDb() {
  try {
    const parsed = JSON.parse(fs.readFileSync(dbPath, 'utf8'));
    if (parsed && typeof parsed === 'object') return parsed;
  } catch {}
  return { schema: 2, chats: {} };
}

function saveDb(db) {
  fs.writeFileSync(dbPath, JSON.stringify(db, null, 2));
}

function localParts(date) {
  const parts = new Intl.DateTimeFormat('en-CA', {
    timeZone,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    hourCycle: 'h23'
  }).formatToParts(date);
  const out = {};
  for (const part of parts) out[part.type] = part.value;
  return out;
}

function localDateKey(date) {
  const p = localParts(date);
  return p.year + '-' + p.month + '-' + p.day;
}

function localStamp(value) {
  const date = value ? new Date(value) : now;
  const p = localParts(Number.isNaN(date.getTime()) ? now : date);
  return p.year + '-' + p.month + '-' + p.day + ' ' + p.hour + ':' + p.minute + ' ' + timeZone;
}

function ageMs(value) {
  const date = new Date(value || 0);
  return Number.isNaN(date.getTime()) ? Infinity : now.getTime() - date.getTime();
}

function isRecentMessage(message) {
  return ageMs(message.at || message.ts || message.telegram_at) <= 72 * 60 * 60 * 1000;
}

function isUsableBooking(booking) {
  if (!booking) return false;
  if (ageMs(booking.updated_at || booking.created_at) > 72 * 60 * 60 * 1000) return false;
  if (booking.date && booking.date < localDateKey(now)) return false;
  return true;
}

const db = loadDb();
db.schema = 2;
db.chats = db.chats && typeof db.chats === 'object' ? db.chats : {};

const chatId = $json.chat_id;
const chat = db.chats[chatId] || { messages: [], booking_state: null };
chat.messages = Array.isArray(chat.messages) ? chat.messages : [];

chat.messages.push({
  role: 'user',
  content: $json.user_text,
  at: nowIso,
  telegram_at: $json.telegram_date,
  message_id: $json.telegram_message_id || null,
  from: $json.from || null
});

chat.messages = chat.messages
  .filter((message) => ageMs(message.at || message.ts || message.telegram_at) <= 30 * 24 * 60 * 60 * 1000)
  .slice(-200);

if (!isUsableBooking(chat.booking_state)) {
  chat.booking_state = null;
}

db.chats[chatId] = chat;
saveDb(db);

const recentMessages = chat.messages
  .filter(isRecentMessage)
  .slice(-16)
  .map((message) => ({
    role: message.role === 'assistant' ? 'assistant' : 'user',
    content: '[' + localStamp(message.at || message.telegram_at) + '] ' + String(message.content || '')
  }));

const bookingIntent = /\b(book|booking|appointment|reserve|reservation|schedule|slot|available|availability|confirm)\b/i.test($json.user_text);
const currentDate = localDateKey(now);
const currentStamp = localStamp(nowIso);
const bookingState = chat.booking_state ? JSON.stringify(chat.booking_state) : 'none';

const system = [
  'You are InterAI on Telegram. Be concise and practical.',
  'Current local date/time is ' + currentStamp + '. Today is ' + currentDate + '. Time zone is ' + timeZone + ' (UTC+03).',
  'Resolve relative dates such as today and tomorrow using only the current local date above, never old chat context.',
  'Only use recent messages included in this prompt. Older history is deliberately excluded and must not affect relative dates.',
  'Current active booking state: ' + bookingState + '.',
  'For any booking, scheduling, slot, availability, or confirmation request, call the manage_booking tool. Do not invent booking confirmations in plain text.',
  'If required booking details are missing, ask for only the missing details.'
].join(' ');

return [{
  json: {
    chat_id: chatId,
    db_path: dbPath,
    user_text: $json.user_text,
    now_iso: nowIso,
    current_date: currentDate,
    timezone: timeZone,
    booking_intent: bookingIntent,
    booking_state: chat.booking_state,
    messages: [
      { role: 'system', content: system },
      ...recentMessages
    ],
    tool_choice: bookingIntent ? { type: 'function', function: { name: 'manage_booking' } } : 'auto',
    tools: [
      {
        type: 'function',
        function: {
          name: 'manage_booking',
          description: 'Resolve and manage booking, appointment, scheduling, availability, or confirmation requests using current local date and active booking state.',
          parameters: {
            type: 'object',
            properties: {
              action: { type: 'string', enum: ['check', 'book', 'confirm', 'cancel', 'ask_details'] },
              service: { type: 'string', description: 'The service or appointment type the user wants.' },
              date: { type: 'string', description: 'Absolute date in YYYY-MM-DD. Resolve today/tomorrow relative to the provided current date.' },
              time: { type: 'string', description: 'Preferred time in HH:mm 24-hour format.' },
              notes: { type: 'string', description: 'Useful details from the user request.' }
            }
          }
        }
      }
    ]
  }
}];

const fs = require('fs');
const prev = $('Prepare Telegram Context').first().json;
const now = new Date(prev.now_iso || new Date().toISOString());
const nowIso = now.toISOString();
const timeZone = prev.timezone || 'Asia/Aden';

function loadDb() {
  try {
    const parsed = JSON.parse(fs.readFileSync(prev.db_path, 'utf8'));
    if (parsed && typeof parsed === 'object') return parsed;
  } catch {}
  return { schema: 2, chats: {} };
}

function saveDb(db) {
  fs.writeFileSync(prev.db_path, JSON.stringify(db, null, 2));
}

function localParts(date) {
  const parts = new Intl.DateTimeFormat('en-CA', {
    timeZone,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    hourCycle: 'h23'
  }).formatToParts(date);
  const out = {};
  for (const part of parts) out[part.type] = part.value;
  return out;
}

function localDateKey(date) {
  const p = localParts(date);
  return p.year + '-' + p.month + '-' + p.day;
}

function addDays(dateKey, days) {
  const [year, month, day] = dateKey.split('-').map(Number);
  const date = new Date(Date.UTC(year, month - 1, day + days, 12, 0, 0));
  return date.toISOString().slice(0, 10);
}

function ageMs(value) {
  const date = new Date(value || 0);
  return Number.isNaN(date.getTime()) ? Infinity : now.getTime() - date.getTime();
}

function usableBooking(booking) {
  if (!booking) return null;
  if (ageMs(booking.updated_at || booking.created_at) > 72 * 60 * 60 * 1000) return null;
  if (booking.date && booking.date < prev.current_date) return null;
  return booking;
}

function normalizeDate(value) {
  if (!value) return null;
  const raw = String(value).trim();
  const lower = raw.toLowerCase();
  if (/^\d{4}-\d{2}-\d{2}$/.test(raw)) return raw;
  if (lower.includes('day after tomorrow') || lower.includes('after tomorrow')) return addDays(prev.current_date, 2);
  if (lower.includes('tomorrow')) return addDays(prev.current_date, 1);
  if (lower.includes('today')) return prev.current_date;
  return raw;
}

function normalizeTime(value) {
  if (!value) return null;
  const raw = String(value).trim();
  const match = raw.match(/^(\d{1,2})(?::(\d{2}))?\s*(am|pm)?$/i);
  if (!match) return raw;
  let hour = Number(match[1]);
  const minute = match[2] || '00';
  const suffix = (match[3] || '').toLowerCase();
  if (suffix === 'pm' && hour < 12) hour += 12;
  if (suffix === 'am' && hour === 12) hour = 0;
  return String(hour).padStart(2, '0') + ':' + minute;
}

function parseToolArgs(toolCall) {
  if (!toolCall?.arguments) return {};
  try {
    return JSON.parse(toolCall.arguments);
  } catch {
    return {};
  }
}

const db = loadDb();
db.schema = 2;
db.chats = db.chats && typeof db.chats === 'object' ? db.chats : {};
const chat = db.chats[prev.chat_id] || { messages: [], booking_state: null };
chat.messages = Array.isArray(chat.messages) ? chat.messages : [];

const message = $json.choices?.[0]?.message || {};
const tool = message.tool_calls?.[0]?.function || null;
let reply = String(message.content || '').trim();
let mode = 'chat';
let booking = null;

if (tool?.name === 'manage_booking') {
  mode = 'booking_tool';
  const active = usableBooking(chat.booking_state || prev.booking_state);
  const args = parseToolArgs(tool);
  const action = args.action || (/\bconfirm\b/i.test(prev.user_text || '') ? 'confirm' : 'check');
  const service = args.service || active?.service || 'general consultation';
  const date = normalizeDate(args.date) || active?.date || null;
  const time = normalizeTime(args.time) || active?.time || null;
  const missing = [];
  if (!date) missing.push('date');
  if (!time) missing.push('time');

  if (action === 'cancel') {
    chat.booking_state = null;
    reply = 'Cancelled the active booking context. Tell me the service, date, and time when you want to start again.';
  } else if (missing.length > 0) {
    chat.booking_state = {
      status: 'needs_details',
      service,
      date,
      time,
      notes: args.notes || null,
      updated_at: nowIso
    };
    reply = 'I can help book ' + service + '. Please provide the missing ' + missing.join(' and ') + '.';
  } else {
    const booked = action === 'book' || action === 'confirm';
    booking = {
      status: booked ? 'booked' : 'available',
      service,
      date,
      time,
      confirmation_code: booked ? 'BK-' + Math.random().toString(36).slice(2, 8).toUpperCase() : null,
      updated_at: nowIso
    };
    chat.booking_state = booking;
    reply = booked
      ? 'Confirmed. Your ' + service + ' is booked for ' + date + ' at ' + time + '. Confirmation code: ' + booking.confirmation_code + '.'
      : 'Yes, ' + date + ' at ' + time + ' is available for ' + service + '. Reply "confirm" to book it.';
  }
}

if (!reply) {
  reply = 'Sorry, I could not generate a response. Please try again.';
}

chat.messages.push({
  role: 'assistant',
  content: reply,
  at: nowIso,
  mode,
  booking
});
chat.messages = chat.messages
  .filter((message) => ageMs(message.at || message.ts || message.telegram_at) <= 30 * 24 * 60 * 60 * 1000)
  .slice(-200);

db.chats[prev.chat_id] = chat;
saveDb(db);

return [{
  json: {
    chat_id: prev.chat_id,
    text: reply,
    mode,
    booking
  }
}];

const escapeHtml = (s) => s
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;');

let text = String($json.text || '');
text = escapeHtml(text);

text = text.replace(/```([\s\S]*?)```/g, (_m, p1) => `<pre><code>${p1.trim()}</code></pre>`);
text = text.replace(/`([^`]+)`/g, '<code>$1</code>');
text = text.replace(/\*\*([^*]+)\*\*/g, '<b>$1</b>');
text = text.replace(/__([^_]+)__/g, '<b>$1</b>');
text = text.replace(/(^|\s)\*([^*]+)\*(?=\s|$)/g, '$1<i>$2</i>');
text = text.replace(/(^|\s)_([^_]+)_(?=\s|$)/g, '$1<i>$2</i>');
text = text.replace(/\[([^\]]+)\]\((https?:\/\/[^\s)]+)\)/g, '<a href="$2">$1</a>');
text = text.replace(/^#{1,6}\s+(.+)$/gm, '<b>$1</b>');
text = text.replace(/^-\s+/gm, '• ');

return [{
  json: {
    chat_id: $json.chat_id,
    text: text
  }
}];
